// HasRecords applies the HasEdge predicate on the "records" edge.
func HasRecords() predicate.BronzeGreenNodeDNSHostedZone {
	return predicate.BronzeGreenNodeDNSHostedZone(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, RecordsTable, RecordsColumn),
		)
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.BronzeGreenNodeDNSRecord
		step.Edge.Schema = schemaConfig.BronzeGreenNodeDNSRecord
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRecordsWith applies the HasEdge predicate on the "records" edge with a given conditions (other predicates).
func HasRecordsWith(preds ...predicate.BronzeGreenNodeDNSRecord) predicate.BronzeGreenNodeDNSHostedZone {
	return predicate.BronzeGreenNodeDNSHostedZone(func(s *sql.Selector) {
		step := newRecordsStep()
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.BronzeGreenNodeDNSRecord
		step.Edge.Schema = schemaConfig.BronzeGreenNodeDNSRecord
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

